// hooks/useInert.ts — for older browsers as polyfill
import { useEffect } from 'react';

export function useInertFallback(ref: React.RefObject<HTMLElement>, inert: boolean) {
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    if (inert) {
      el.setAttribute('aria-hidden', 'true');
      const focusable = el.querySelectorAll<HTMLElement>('button, a, input, textarea, select, [tabindex]');
      const original = new Map<HTMLElement, string | null>();
      focusable.forEach((f) => {
        original.set(f, f.getAttribute('tabindex'));
        f.setAttribute('tabindex', '-1');
      });
      return () => {
        el.removeAttribute('aria-hidden');
        original.forEach((tabindex, f) => {
          if (tabindex === null) f.removeAttribute('tabindex');
          else f.setAttribute('tabindex', tabindex);
        });
      };
    }
  }, [ref, inert]);
}

