import { useState, useEffect } from 'react';
import { PanelLeftClose, PanelLeft } from 'lucide-react';

export function CollapsibleSidebar({ items }: { items: { id: string; label: string; icon: React.ReactNode; href: string }[] }) {
  const [collapsed, setCollapsed] = useState(false);

  useEffect(() => {
    const stored = localStorage.getItem('sidebar-collapsed');
    if (stored) setCollapsed(stored === 'true');

    const onKey = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === '\\') {
        e.preventDefault();
        setCollapsed((c) => {
          const next = !c;
          localStorage.setItem('sidebar-collapsed', String(next));
          return next;
        });
      }
    };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, []);

  return (
    <aside
      className="@container/sidebar flex flex-col border-r bg-white transition-[width] duration-200"
      style={{ width: collapsed ? 64 : 240 }}
    >
      <div className="flex items-center justify-end p-2 border-b">
        <button
          type="button"
          onClick={() => { const next = !collapsed; setCollapsed(next); localStorage.setItem('sidebar-collapsed', String(next)); }}
          aria-label={collapsed ? 'Expand sidebar' : 'Collapse sidebar'}
          aria-expanded={!collapsed}
          className="flex h-9 w-9 items-center justify-center rounded hover:bg-neutral-100"
        >
          {collapsed ? <PanelLeft className="h-4 w-4" /> : <PanelLeftClose className="h-4 w-4" />}
        </button>
      </div>
      <nav className="flex-1 overflow-y-auto p-2" aria-label="Primary">
        <ul className="space-y-1">
          {items.map((item) => (
            <li key={item.id}>
              <a
                href={item.href}
                title={item.label}
                className="
                  flex items-center gap-3 min-h-11 px-3 rounded
                  hover:bg-neutral-100
                  text-sm
                "
              >
                <span className="flex-none">{item.icon}</span>
                <span className="truncate @max-[100px]/sidebar:hidden">{item.label}</span>
              </a>
            </li>
          ))}
        </ul>
      </nav>
    </aside>
  );
}

