import { useRef, useState } from 'react';

export function DraggableCarousel({ slides }: { slides: React.ReactNode[] }) {
  const trackRef = useRef<HTMLDivElement>(null);
  const [index, setIndex] = useState(0);
  const dragRef = useRef({ startX: 0, scrollStart: 0, isDragging: false });

  const onPointerDown = (e: React.PointerEvent) => {
    if (!trackRef.current) return;
    dragRef.current = { startX: e.clientX, scrollStart: trackRef.current.scrollLeft, isDragging: true };
    trackRef.current.setPointerCapture(e.pointerId);
  };

  const onPointerMove = (e: React.PointerEvent) => {
    if (!dragRef.current.isDragging || !trackRef.current) return;
    trackRef.current.scrollLeft = dragRef.current.scrollStart - (e.clientX - dragRef.current.startX);
  };

  const onPointerUp = () => {
    if (!trackRef.current) return;
    dragRef.current.isDragging = false;
    // Snap to nearest
    const slideW = trackRef.current.clientWidth;
    const newIndex = Math.round(trackRef.current.scrollLeft / slideW);
    setIndex(newIndex);
    trackRef.current.scrollTo({ left: newIndex * slideW, behavior: 'smooth' });
  };

  return (
    <div className="relative">
      <div
        ref={trackRef}
        onPointerDown={onPointerDown}
        onPointerMove={onPointerMove}
        onPointerUp={onPointerUp}
        onPointerCancel={onPointerUp}
        className="
          flex overflow-x-auto snap-x snap-mandatory
          [scrollbar-width:none] [&::-webkit-scrollbar]:hidden
        "
        style={{ scrollSnapType: 'x mandatory', touchAction: 'pan-y', cursor: 'grab' }}
      >
        {slides.map((s, i) => (
          <div key={i} className="flex-none w-full snap-start">{s}</div>
        ))}
      </div>
      {/* Dots indicator */}
      <div className="flex justify-center gap-2 mt-3">
        {slides.map((_, i) => (
          <button
            key={i}
            onClick={() => {
              setIndex(i);
              trackRef.current?.scrollTo({ left: i * trackRef.current.clientWidth, behavior: 'smooth' });
            }}
            aria-label={`Go to slide ${i + 1}`}
            aria-current={i === index ? 'true' : undefined}
            className={`h-2 w-2 rounded-full ${i === index ? 'bg-black' : 'bg-neutral-300'}`}
          />
        ))}
      </div>
    </div>
  );
}

