export function TabbedPage({ tabs, content }: { tabs: { id: string; label: string }[]; content: (id: string) => React.ReactNode }) {
  const bp = useBreakpoint();
  const [activeId, setActiveId] = useState(tabs[0].id);
  const [pickerOpen, setPickerOpen] = useState(false);
  const active = tabs.find((t) => t.id === activeId);

  if (bp === 'mobile') {
    return (
      <div className="flex flex-col h-dvh">
        <header className="border-b bg-white">
          <button
            type="button"
            onClick={() => setPickerOpen(true)}
            className="flex items-center gap-1 px-4 py-3 min-h-12 w-full text-left"
          >
            <span className="font-medium">{active?.label}</span>
            <ChevronDown className="h-4 w-4" />
          </button>
        </header>
        <main className="flex-1 overflow-y-auto">{content(activeId)}</main>
        <AdaptiveDialog open={pickerOpen} onClose={() => setPickerOpen(false)} title="Select section">
          <ul className="divide-y">
            {tabs.map((t) => (
              <li key={t.id}>
                <button
                  type="button"
                  onClick={() => { setActiveId(t.id); setPickerOpen(false); }}
                  aria-current={activeId === t.id ? 'page' : undefined}
                  className={`w-full text-left min-h-14 px-2 ${activeId === t.id ? 'font-medium' : ''}`}
                >{t.label}</button>
              </li>
            ))}
          </ul>
        </AdaptiveDialog>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-dvh">
      <nav role="tablist" className="flex gap-1 border-b px-4">
        {tabs.map((t) => (
          <button
            key={t.id}
            role="tab"
            aria-selected={activeId === t.id}
            onClick={() => setActiveId(t.id)}
