              min-h-11 px-4 text-sm border-b-2 -mb-px
              ${activeId === t.id ? 'border-blue-500 text-blue-700 font-medium' : 'border-transparent text-neutral-600'}
            `}
          >{t.label}</button>
        ))}
      </nav>
      <main className="flex-1 overflow-y-auto p-4">{content(activeId)}</main>
    </div>
  );
}

