import { ArrowUp, ArrowDown, ArrowUpDown } from 'lucide-react';

export function SortableHeader<K extends string>({ field, sortKey, sortDir, onSort, children }: {
  field: K;
  sortKey: K | null;
  sortDir: 'asc' | 'desc' | null;
  onSort: (key: K) => void;
  children: React.ReactNode;
}) {
