  return (
    <th
      scope="col"
      aria-sort={active ? (sortDir === 'asc' ? 'ascending' : 'descending') : 'none'}
      className="px-3 py-2 text-left font-medium border-b"
    >
      <button
        type="button"
        onClick={() => onSort(field)}
        className="flex items-center gap-1 hover:underline focus-visible:outline-2 focus-visible:outline-blue-500"
      >
        {children}
        {active ? (
          sortDir === 'asc' ? <ArrowUp className="h-3.5 w-3.5" aria-hidden /> : <ArrowDown className="h-3.5 w-3.5" aria-hidden />
        ) : (
          <ArrowUpDown className="h-3.5 w-3.5 text-neutral-400" aria-hidden />
