import { useEffect } from 'react';
import { X } from 'lucide-react';

export function ConfigurableDialog({ open, onClose, title, children, dismissOnBackdrop = true, dismissOnEscape = true }: {
  open: boolean;
  onClose: () => void;
  title: string;
  children: React.ReactNode;
  dismissOnBackdrop?: boolean;
  dismissOnEscape?: boolean;
}) {
  useEffect(() => {
    if (!open || !dismissOnEscape) return;
    const onKey = (e: KeyboardEvent) => e.key === 'Escape' && onClose();
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [open, onClose, dismissOnEscape]);

  if (!open) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center">
      <div
        className="absolute inset-0 bg-black/50"
        onClick={dismissOnBackdrop ? onClose : undefined}
        aria-hidden
      />
      <div
        role="dialog"
        aria-modal="true"
        aria-labelledby="dialog-title"
        className="relative bg-white rounded-xl shadow-2xl max-w-md w-full max-h-[85dvh] overflow-y-auto m-4"
      >
        <header className="flex items-center justify-between border-b px-5 py-3">
          <h2 id="dialog-title" className="font-semibold">{title}</h2>
          <button onClick={onClose} aria-label="Close" className="flex h-11 w-11 items-center justify-center -mr-2"><X className="h-5 w-5" /></button>
        </header>
        <div className="p-5">{children}</div>
      </div>
    </div>
  );
}

