// hooks/useViewportRef.ts
import { useEffect, useRef } from 'react';

export function useViewportRef(callback: (size: { width: number; height: number }) => void) {
  const callbackRef = useRef(callback);
  callbackRef.current = callback;

  useEffect(() => {
    const onResize = () => {
      callbackRef.current({ width: window.innerWidth, height: window.innerHeight });
    };
    onResize();
    window.addEventListener('resize', onResize, { passive: true });
    return () => window.removeEventListener('resize', onResize);
  }, []);
}

// components/CanvasViz.tsx
import { useRef } from 'react';
import { useViewportRef } from '@/hooks/useViewportRef';

export function CanvasViz() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useViewportRef(({ width, height }) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    canvas.width = width;
    canvas.height = height;
    // Redraw without React re-render
    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.fillStyle = '#3b82f6';
      ctx.fillRect(0, 0, width, height);
    }
  });

  return <canvas ref={canvasRef} className="block" />;
}

