import { useRef } from 'react';

type Sample = { x: number; t: number };

export function usePointerSwipe(onSwipe: (direction: 'left' | 'right' | 'none', velocity: number) => void) {
  const samples = useRef<Sample[]>([]);
  const startX = useRef(0);

  const onPointerDown = (e: React.PointerEvent) => {
    samples.current = [{ x: e.clientX, t: performance.now() }];
    startX.current = e.clientX;
  };

  const onPointerMove = (e: React.PointerEvent) => {
    samples.current.push({ x: e.clientX, t: performance.now() });
    if (samples.current.length > 10) samples.current.shift();
  };

  const onPointerUp = (e: React.PointerEvent) => {
    const recent = samples.current.slice(-5);
    if (recent.length < 2) { onSwipe('none', 0); return; }
    const first = recent[0];
    const last = recent[recent.length - 1];
    const velocity = (last.x - first.x) / (last.t - first.t); // px/ms
    const distance = e.clientX - startX.current;

    if (Math.abs(velocity) > 0.5 || Math.abs(distance) > 100) {
      onSwipe(distance > 0 ? 'right' : 'left', velocity);
    } else {
      onSwipe('none', velocity);
    }
  };

  return { onPointerDown, onPointerMove, onPointerUp };
}

