// components/ResizableHeader.tsx
import { useRef } from 'react';

export function ResizableHeader({ width, onResize, children }: { width: number; onResize: (w: number) => void; children: React.ReactNode }) {
  const startX = useRef(0);
  const startW = useRef(0);

  const onPointerDown = (e: React.PointerEvent) => {
    e.stopPropagation();
    startX.current = e.clientX;
    startW.current = width;
    (e.target as HTMLElement).setPointerCapture(e.pointerId);
  };

  const onPointerMove = (e: React.PointerEvent) => {
    if (!(e.target as HTMLElement).hasPointerCapture?.(e.pointerId)) return;
    onResize(Math.max(80, startW.current + (e.clientX - startX.current)));
  };

  const onKeyDown = (e: React.KeyboardEvent) => {
    if (e.shiftKey && e.key === 'ArrowLeft') { e.preventDefault(); onResize(Math.max(80, width - 10)); }
    if (e.shiftKey && e.key === 'ArrowRight') { e.preventDefault(); onResize(width + 10); }
  };

  return (
    <th style={{ width, minWidth: width }} onKeyDown={onKeyDown} tabIndex={0} className="relative px-3 py-2 text-left font-medium border-b">
      {children}
      <span
        role="separator"
        aria-orientation="vertical"
        aria-valuenow={width}
        onPointerDown={onPointerDown}
        onPointerMove={onPointerMove}
        className="
          absolute right-0 top-0 bottom-0 cursor-col-resize
          w-1 [@media(pointer:coarse)]:w-2
          hover:bg-blue-400
        "
      />
    </th>
  );
}

// components/UploadZone.tsx
import { useState } from 'react';
import { Camera, Upload, Folder } from 'lucide-react';
import { useMediaQuery } from '@/hooks/useMediaQuery';

export function UploadZone({ onFiles }: { onFiles: (files: File[]) => void }) {
  const isMobile = useMediaQuery('(pointer: coarse)', true);
  const [dragOver, setDragOver] = useState(false);

  if (isMobile) {
    return (
      <div className="grid grid-cols-2 gap-2">
        <label className="flex flex-col items-center gap-2 min-h-32 p-4 border-2 border-dashed border-neutral-300 rounded-lg cursor-pointer hover:bg-neutral-50">
          <Camera className="h-8 w-8 text-neutral-400" />
          <span className="text-sm">Take photo</span>
          <input type="file" accept="image/*" capture="environment" onChange={(e) => onFiles(Array.from(e.target.files ?? []))} className="sr-only" />
        </label>
        <label className="flex flex-col items-center gap-2 min-h-32 p-4 border-2 border-dashed border-neutral-300 rounded-lg cursor-pointer hover:bg-neutral-50">
          <Folder className="h-8 w-8 text-neutral-400" />
          <span className="text-sm">Choose file</span>
          <input type="file" accept="image/*" onChange={(e) => onFiles(Array.from(e.target.files ?? []))} className="sr-only" />
        </label>
      </div>
    );
  }

  return (
    <div
      onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
      onDragLeave={() => setDragOver(false)}
      onDrop={(e) => {
        e.preventDefault();
        setDragOver(false);
        onFiles(Array.from(e.dataTransfer.files));
      }}
      className={`
        flex flex-col items-center gap-3 min-h-48 p-8
        border-2 border-dashed rounded-lg
        ${dragOver ? 'border-blue-500 bg-blue-50' : 'border-neutral-300'}
      `}
    >
      <Upload className="h-12 w-12 text-neutral-400" />
      <p>Drag files here or <label className="text-blue-600 underline cursor-pointer">browse<input type="file" multiple onChange={(e) => onFiles(Array.from(e.target.files ?? []))} className="sr-only" /></label></p>
    </div>
  );
}

