// components/AdaptiveSearch.tsx
import { useState, useRef, useEffect } from 'react';
import { useBreakpoint } from '@/hooks/useBreakpoint';
import { Search, X } from 'lucide-react';

export function AdaptiveSearch() {
  const bp = useBreakpoint();
  const [expanded, setExpanded] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (expanded) inputRef.current?.focus();
  }, [expanded]);

  if (bp === 'mobile') {
    if (!expanded) {
      return (
        <button
          type="button"
          onClick={() => setExpanded(true)}
          aria-label="Open search"
          className="flex h-11 w-11 items-center justify-center"
        ><Search className="h-5 w-5" /></button>
      );
    }
    return (
      <div className="flex items-center gap-1 flex-1">
        <input
          ref={inputRef}
          type="search"
          placeholder="Search"
          aria-label="Search"
          className="flex-1 min-h-11 rounded border bg-white px-3 text-base"
        />
        <button
          onClick={() => setExpanded(false)}
          aria-label="Close search"
          className="flex h-11 w-11 items-center justify-center"
        ><X className="h-5 w-5" /></button>
      </div>
    );
  }

  return (
    <div className="relative">
      <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-neutral-400" aria-hidden />
      <input
        type="search"
        placeholder="Search"
        aria-label="Search"
        className="w-64 min-h-9 rounded border bg-neutral-50 pl-9 pr-3 text-sm"
      />
    </div>
  );
}
